document.addEventListener("DOMContentLoaded",function(){const n=document.querySelector('input[name="__RequestVerificationToken"]'),t=n?n.value:"";document.querySelectorAll(".pin-btn").forEach(n=>{n.addEventListener("click",async function(){const n=this.getAttribute("data-note-id");try{const i=await fetch(`/Notes/Pin?id=${n}`,{method:"POST",headers:{RequestVerificationToken:t,"X-Requested-With":"XMLHttpRequest"}});i.ok&&location.reload()}catch(i){console.error("Error pinning note:",i)}})});document.querySelectorAll(".unpin-btn").forEach(n=>{n.addEventListener("click",async function(){const n=this.getAttribute("data-note-id");try{const i=await fetch(`/Notes/Unpin?id=${n}`,{method:"POST",headers:{RequestVerificationToken:t,"X-Requested-With":"XMLHttpRequest"}});i.ok&&location.reload()}catch(i){console.error("Error unpinning note:",i)}})})});